--小游戏字段interactive的解析
function ModelActivityMiniGame:ParseMiniGameInteractiveCfg(webCfg)
    local list = {}
    if webCfg.type == 1 then
        local tempData = string.split(webCfg.interactive, ",")
        list.maxResultText = tempData[1]
        list.minResultText = tempData[2]
        list.winAnimName = tempData[3]
        list.winSoundName = tempData[4]
        list.failText = tempData[5]
    elseif webCfg.type == 2 then
        local tempData = string.split(webCfg.interactive, ",")
        list.winSpinName = tempData[1]
        list.winSoundName = tempData[2]
        list.failText = tempData[3]
        list.cameraArg = tempData[4]
    elseif webCfg.type == 3 then
        local tempData = string.split(webCfg.interactive, ",")
        list.changeManifestation = {}
        for k, v in ipairs(tempData) do
            table.insert(list.changeManifestation, v)
        end
    else
        printInfoNR2("ModelActivityMiniGame", "not type to parse")
    end

    return list
end

--type3的Interactive解析
function ModelActivityMiniGame:ParseInteractiveCfgType_3(interactive)
    local tempData = string.split(interactive, "|")

    local list = {}
    list.temperature = checknumber(tempData[1])
    list.maskBg = tempData[2]
    list.maskPos = tempData[3]
    list.maskAlpha = checknumber(tempData[4])
    list.textId = checknumber(tempData[5])

    return list
end

--type3的温度档位转为index  
function ModelActivityMiniGame:GetCherryBombTemperature(webCfg)
    local list = {}
    if webCfg.type == 3 then
        local tempData = string.split(webCfg.interactive, ",")

        for k, v in ipairs(tempData) do
            local tempData_2 = string.split(v, "|")
            local temperature = checknumber(tempData_2[1])
            table.insert(list, temperature)
        end
    end
    return list
end

function ModelActivityMiniGame:GetCherryBombTemperatureIndex(temperatureList, temperature)
    local index = 0
    for k, v in ipairs(temperatureList) do
        if checknumber(temperature) >= checknumber(v) then
            index = k
        else
            return index
        end
    end

    return index
end

--解析配置的moreInfo部分
function ModelActivityMiniGame:ParseCherryBombMoreInfo(entryCfg)
    local list = {}
    local tempData = string.split(entryCfg.moreInfo, ",")
    list.addTemperatureValue = checknumber(tempData[1])
    list.initTemperatureValue = checknumber(tempData[2])
    list.maxTemperatureValue = checknumber(tempData[3])
    list.winCondition = checknumber(tempData[4])
    list.cherryImg = {}
    table.insert(list.cherryImg, tempData[5])
    table.insert(list.cherryImg, tempData[6])
    table.insert(list.cherryImg, tempData[7])

    return list
end

--解析Turntable的moreInfo 
function ModelActivityMiniGame:ParseTurntableMoreInfo(entryCfg)
    local list = {}
    local tempData = string.split(entryCfg.moreInfo, ",")
    list.totalTime = checknumber(tempData[1])
    local speedTempData = string.split(tempData[2], "|")
    list.rotateSpeed = {}
    for k, v in ipairs(speedTempData) do
        table.insert(list.rotateSpeed, checknumber(v))
    end

    list.totalCloth = checknumber(tempData[3])

    return list
end

--解析Dice的moreInfo 
function ModelActivityMiniGame:ParseDiceMoreInfo(entryCfg)
    local list = {}
