    list.maxTemperatureValue = checknumber(tempData[3])

    return list
end


--获取对应类型的游戏界面
function ModelActivityMiniGame:GetMiniGameWndName(miniGameType)
    if not self.miniGameWndName then
        self.miniGameWndName = {}
        self.miniGameWndName[1] = "UIDice"
        self.miniGameWndName[2] = "UITurntable"
        self.miniGameWndName[3] = "UICherryBomb"
    end

    if not self.miniGameWndName[miniGameType] or string.isempty(self.miniGameWndName[miniGameType]) then
        printInfoNR2("ModelActivityMiniGame", "not miniGame Wnd--" .. miniGameType)
    end

    return self.miniGameWndName[miniGameType]
end

function ModelActivityMiniGame:GetFloatImgName(isWin)
    if isWin then
        return "activity_159_txt_17"
    else
        return "activity_159_txt_18"
    end
end

function ModelActivityMiniGame:Parse159ActivityMoreInfo(moreInfo)
    --返回 任务列表 已经看过的剧情道具Id列表  已获得的剧情道具  剧情进度奖励
    -- taskList   progItemList    plotRewardIdList  recCollectReward
    local tempData = JSON.decode(moreInfo)
    local tempData_2 = string.split(tempData.taskList, ",")

    --任务列表
    local taskList = {}
    for k, v in ipairs(tempData_2) do
        table.insert(taskList, checknumber(v))
    end

    -- 已经看过的剧情道具Id列表
    local tempData_3 = string.split(tempData.progItemList, ",")
    local progItemList = {}
    for k, v in ipairs(tempData_3) do
        progItemList[checknumber(v)] = true
    end

    -- 已获得的剧情道具
    local tempData_4 = string.split(tempData.plotRewardIdList, ",")
    local plotRewardIdList = {}
    for k, v in ipairs(tempData_4) do
        plotRewardIdList[checknumber(v)] = true
    end
    
    -- 剧情进度奖励
    local tempData_5 = string.split(tempData.recCollectReward, ",")
    local recCollectReward={}
    for k, v in ipairs(tempData_5) do
        recCollectReward[checknumber(v)] = true
    end
    
    return  taskList,progItemList,plotRewardIdList,recCollectReward
end

