--region 协议部分 --------------------------------------------------------------------------------
function ModelActivityMiniGame:SendActivityMiniGameOptReq(gameType, sid, pageId, option, params)
    local pb = LProtoHelper.CreateProto(LProtoIds.ActivityMiniGameOptReq)
    pb.gameType = gameType
    pb.sid = sid
    pb.pageId = pageId
    pb.opt = option

    if params then
        pb.params = params
    end
    SendMessage(pb, LProtoIds.ActivityMiniGameOptReq)

end

function ModelActivityMiniGame:OnActivityMiniGameOptResp(pb)
    local tempData = {}
    tempData.gameType = pb.gameType
    tempData.sid = pb.sid
    tempData.params = pb.params
    tempData.opt = pb.opt

    local items = pb.itemList          --获得奖励物品
    local itemList = {}
    for i, v in ipairs(items or {}) do
        local item = StructRewardItem:New()
        item:CreateByPb(v)
        table.insert(itemList, item)
    end
    tempData.items = itemList

    tempData.progress = pb.progress
    tempData.resultStr = pb.resultStr
    tempData.common = pb.common
    tempData.reward = pb.reward
    tempData.isWin = pb.isWin
    tempData.endStatus = pb.endStatus
    FireEvent(EventNames.MINIGAME_OPT_RESULT, tempData)
end


